class BinaryExpressionWrappingRuleReproduceTest {
    private val binaryExpressionWrappingRuleAssertThat = KtLintAssertThat.assertThatRule { BinaryExpressionWrappingRule() }

    @Test
    fun `Issue 2157 - Endless loop in wrapping binary expression after elvis operator`() {
        val code =
            """
            val a = b ?: c
            """.trimIndent()

        binaryExpressionWrappingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to "10")
            .hasLintViolationWithoutAutoCorrect(1, 11, "Line is exceeding max line length")
